// Step 1: F5後にtokensが保持されるか確認

chrome.storage.local.get('relay_current', r => console.log(r.relay_current))

// Step 2: 80%バナーテスト（heavy mode T*=13000 の80% = 10400）

chrome.storage.local.get('relay_current', r => {

  const c = r.relay_current;

  c.estimated_tokens = 10500;

  chrome.storage.local.set({relay_current: c});

})

// Step 3: 100%超バナーテスト

chrome.storage.local.get('relay_current', r => {

  const c = r.relay_current;

  c.estimated_tokens = 14000;

  chrome.storage.local.set({relay_current: c});

})
